/**
 * Tests for https://github.com/pinterest/ktlint/issues/2028
 *
 * The function-signature rule should not merge annotated expression with the function signature
 * as that would result in a violation of the annotation rule.
 */
class FunctionSignatureRuleAnnotatedExpressionTest {
    private val functionSignatureWrappingRuleAssertThat = assertThatRule { FunctionSignatureRule() }

    @Nested
    inner class `Given a function with an annotated expression body on a separate line` {
        @ParameterizedTest(name = "bodyExpressionWrapping: {0}")
        @EnumSource(
            value = FunctionSignatureRule.FunctionBodyExpressionWrapping::class,
        )
        fun `Given an annotated expression body on a separate line then do not merge with the function signature`(
            bodyExpressionWrapping: FunctionSignatureRule.FunctionBodyExpressionWrapping,
        ) {
            val code =
                """
                private fun getErrorMessage(value: String): String =
                    @Suppress("DEPRECATION")
                    customMessage.takeUnless { it.isEmpty() } ?: String.format(DEFAULT_ERROR_MESSAGE, value)
                """.trimIndent()
            functionSignatureWrappingRuleAssertThat(code)
                .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
                .withEditorConfigOverride(FUNCTION_BODY_EXPRESSION_WRAPPING_PROPERTY to bodyExpressionWrapping)
                .hasNoLintViolations()
        }

        @Test
        fun `Given a multiline function signature with an annotated expression body on a separate line then do not merge with the function signature`() {
            val code =
                """
                private fun getErrorMessage(
                    value: String,
                    otherValue: String
                ): String =
                    @Suppress("DEPRECATION")
                    customMessage.takeUnless { it.isEmpty() } ?: String.format(DEFAULT_ERROR_MESSAGE, value)
                """.trimIndent()
            functionSignatureWrappingRuleAssertThat(code)
                .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
                .hasNoLintViolations()
        }

        @Test
        fun `Given a function with an annotated expression that would fit on one line then still do not merge`() {
            val code =
                """
                fun foo(): String =
                    @Suppress("DEPRECATION")
                    bar
                """.trimIndent()
            functionSignatureWrappingRuleAssertThat(code)
                .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 100)
                .hasNoLintViolations()
        }

        @Test
        fun `Given a multiline function signature without explicit return type and an annotated expression body on a separate line then do not merge with the function signature`() {
            val code =
                """
                private fun getErrorMessage(
                    value: String,
                    otherValue: String
                ) =
                    @Suppress("DEPRECATION")
                    customMessage.takeUnless { it.isEmpty() } ?: String.format(DEFAULT_ERROR_MESSAGE, value)
                """.trimIndent()
            functionSignatureWrappingRuleAssertThat(code)
                .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 120)
                .hasNoLintViolations()
        }
    }

    @Nested
    inner class `Given a function with a non-annotated expression body` {
        @Test
        fun `Given that a non-annotated expression body fits on the same line then it can be merged`() {
            val code =
                """
                fun foo(): String =
                    bar
                """.trimIndent()
            val formattedCode =
                """
                fun foo(): String = bar
                """.trimIndent()
            functionSignatureWrappingRuleAssertThat(code)
                .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 100)
                .hasLintViolation(1, 20, "First line of body expression fits on same line as function signature")
                .isFormattedAs(formattedCode)
        }
    }
}
